import{g as e}from"./index-BbENECY5.js";var t={getAll:async t=>(await e.get(`/payroll/payroll/`,{params:t})).data,create:async t=>(await e.post(`/payroll/payroll/`,t)).data,bulkGenerate:async t=>(await e.post(`/payroll/payroll/bulk-generate/`,t)).data,updateStatus:async(t,n)=>(await e.patch(`/payroll/payroll/${t}/`,{status:n})).data,getStats:async()=>{let t=await e.get(`/payroll/payroll/`),n=t.data.results||t.data;return{totalNetPay:n.reduce((e,t)=>e+parseFloat(t.net_pay),0),totalBonus:n.reduce((e,t)=>e+parseFloat(t.bonus),0),count:n.length}}};export{t};